svg.script:
var circles = document.querySelectorAll('circle[data-score]');
var PE = 850;
for (var i = 0; i < circles.length; i++) {
  (function(c) {
    c.addEventListener('click', function(e) {
      var sc = this.getAttribute('data-score');
      var id = this.getAttribute('data-id');
      var act = this.getAttribute('data-action');
      var cx = parseFloat(this.getAttribute('cx'));
      var cy = parseFloat(this.getAttribute('cy'));
      var bg = document.getElementById('popup-bg');
      var l1 = document.getElementById('popup-line1');
      var l2 = document.getElementById('popup-line2');
      var ox = (cx > PE) ? -330 : 15;
      bg.setAttribute('x', cx + ox);
      bg.setAttribute('y', cy - 55);
      bg.setAttribute('opacity', '0.95');
      bg.setAttribute('visibility', 'visible');
      l1.setAttribute('x', cx + ox + 12);
      l1.setAttribute('y', cy - 38);
      l1.setAttribute('opacity', '1');
      l1.setAttribute('visibility', 'visible');
      l2.setAttribute('x', cx + ox + 12);
      l2.setAttribute('y', cy - 20);
      l2.setAttribute('opacity', '1');
      l2.setAttribute('visibility', 'visible');
      l1.textContent = 'run_id: ' + id + ' | ' + act + ' | composite: ' + sc;
      l2.textContent = 'benchmark: auto-eval | stage: evaluate';
      e.stopPropagation();
    });
  })(circles[i]);
}
document.addEventListener('click', function(e) {
  var bg = document.getElementById('popup-bg');
  bg.setAttribute('opacity', '0');
  bg.setAttribute('visibility', 'hidden');
  document.getElementById('popup-line1').setAttribute('opacity', '0');
  document.getElementById('popup-line1').setAttribute('visibility', 'hidden');
  document.getElementById('popup-line2').setAttribute('opacity', '0');
  document.getElementById('popup-line2').setAttribute('visibility', 'hidden');
});
